-\alpha_1 & -\alpha_2 & \cdots & -\alpha_{n-1} & -\alpha_n - \beta_n \\
1 & 0 & \cdots & 0 & -\beta_{n-1} \\
0 & 1 & \cdots & 0 & -\beta_{n-2} \\
\vdots & \vdots & \ddots & \vdots & \vdots \\
0 & 0 & \cdots & 1 & -\beta_1
\end{bmatrix}
\end{equation}

